// Уязвимый код: пользовательский ввод попадает прямо в значение
db.products.find({ "price": userInput })

// Атакующий подставляет вместо значения оператор:
{ "$gt": 0 }

// Итоговый запрос вернёт ВСЕ товары с ценой > 0 (утечка данных):
db.products.find({ "price": { "$gt": 0 } })

// В MongoDB при дублировании ключа в документе побеждает ПОСЛЕДНЕЕ вхождение.
// Итоговое значение "id" будет "100":
{"id":"10", "id":"100"}
